    68→  /**
    69→   * Generate a response from Claude
    70→   */
    71→  static async generate(
    72→    messages: AIMessage[],
    73→    options: GenerateOptions = {}
    74→  ): Promise<string> {
    75→    const client = await this.getClient();
    76→
    77→    const model = options.model || 'haiku';
    78→    const maxTokens = options.maxTokens || 1024;
    79→    const temperature = options.temperature || 1.0;
    80→
    81→    const response = await client.messages.create({
    82→      model: this.MODELS[model],
    83→      max_tokens: maxTokens,
    84→      temperature,
    85→      system: options.systemPrompt,
    86→      messages: messages.map((msg) => ({
    87→        role: msg.role,
    88→        content: msg.content,
    89→      })),
    90→    });
    91→
    92→    if (!response.content.length || response.content[0].type !== 'text') {
    93→      throw new Error('Empty or unexpected response from Claude');
    94→    }
    95→    return response.content[0].text;
    96→  }
