   199→  static async parseCalendarEvent(
   200→    input: string
   201→  ): Promise<{ summary: string; startTime: string; endTime: string; description?: string }> {
   202→    const now = new Date();
   203→    const systemPrompt = `You are a calendar parsing assistant. Parse the user's natural language into a calendar event. The current date/time is ${now.toISOString()}. Return ONLY valid JSON with these fields: {"summary": "event title", "startTime": "ISO 8601 datetime", "endTime": "ISO 8601 datetime", "description": "optional description or empty string"}. If duration isn't specified, default to 1 hour. Interpret relative dates like "tomorrow", "next Friday", etc. relative to the current time.`;
