   445→  /**
   446→   * Parse a natural language command into tool calls using the Anthropic tool-use API.
   447→   */
   448→  static async parseCommand(input: string, memoryContext?: string): Promise<ParsedCommand> {
   449→    const client = await this.getClient();
   450→
   451→    const now = new Date();
   452→    let systemPrompt = `You are a personal command center assistant. The current date/time is ${now.toISOString()}. Parse the user's natural language command and call the appropriate tool(s). Interpret relative dates like "tomorrow", "next Friday", etc. relative to the current time. If the command requires multiple steps, call multiple tools.`;
   453→
   454→    if (memoryContext) {
   455→      systemPrompt += `\n\n${memoryContext}`;
   456→    }
   457→
   458→    const response = await client.messages.create({
   459→      model: this.MODELS.haiku,
   460→      max_tokens: 1024,
   461→      system: systemPrompt,
   462→      tools: this.COMMAND_TOOLS,
   463→      messages: [{ role: 'user', content: input }],
   464→    });
   465→
   466→    const toolCalls: ToolCall[] = [];
   467→    let explanation = '';
   468→
   469→    for (const block of response.content) {
   470→      if (block.type === 'tool_use') {
   471→        toolCalls.push({
   472→          name: block.name,
   473→          input: block.input as Record<string, any>,
   474→        });
   475→      } else if (block.type === 'text') {
   476→        explanation += block.text;
   477→      }
   478→    }
   479→
   480→    return { toolCalls, explanation };
   481→  }
   482→
   483→  /**
   484→   * Execute a single tool call by routing to the appropriate service.
   485→   */
   486→  static async executeToolCall(toolCall: ToolCall): Promise<string> {
   487→    const { name, input } = toolCall;
   488→
   489→    switch (name) {
   490→      case 'send_message': {
   491→        const { IMessageService } = await import('../imessage/IMessageService.js');
   492→        const service = new IMessageService();
   493→        const result = await service.sendMessage(input.recipient, input.text);
   494→        return result.success ? `Sent message to ${input.recipient}` : `Failed: ${result.message}`;
   495→      }
   496→
   497→      case 'send_email': {
   498→        const { EmailSyncService } = await import('../gmail/EmailSyncService.js');
   499→        const service = new EmailSyncService();
   500→        await service.sendEmail(input.to, input.subject, input.body);
   501→        return `Sent email to ${input.to}: "${input.subject}"`;
   502→      }
   503→
   504→      case 'create_event': {
   505→        const { CalendarSyncService } = await import('../calendar/CalendarSyncService.js');
   506→        const service = new CalendarSyncService();
   507→        await service.createEvent(
   508→          input.summary,
   509→          new Date(input.start_time),
   510→          new Date(input.end_time),
   511→          input.description || ''
   512→        );
   513→        return `Created event: ${input.summary}`;
   514→      }
   515→
   516→      case 'search_emails': {
   517→        const { EmailSyncService } = await import('../gmail/EmailSyncService.js');
   518→        const service = new EmailSyncService();
   519→        const results = service.searchEmails(input.query);
   520→        if (results.length === 0) return `No emails found for "${input.query}"`;
   521→        return `Found ${results.length} emails:\n${results.slice(0, 5).map((e) => `  - ${e.subject} (${e.from_address})`).join('\n')}`;
   522→      }
   523→
   524→      case 'search_events': {
   525→        const { CalendarSyncService } = await import('../calendar/CalendarSyncService.js');
   526→        const service = new CalendarSyncService();
   527→        const results = service.searchEvents(input.query);
   528→        if (results.length === 0) return `No events found for "${input.query}"`;
   529→        return `Found ${results.length} events:\n${results.slice(0, 5).map((e) => `  - ${e.summary}`).join('\n')}`;
   530→      }
   531→
   532→      case 'search_messages': {
   533→        const { IMessageService } = await import('../imessage/IMessageService.js');
   534→        const service = new IMessageService();
   535→        const results = service.searchMessages(input.query);
   536→        if (results.length === 0) return `No messages found for "${input.query}"`;
   537→        return `Found ${results.length} messages:\n${results.slice(0, 5).map((m) => `  - ${m.sender_id}: ${m.text.slice(0, 50)}`).join('\n')}`;
   538→      }
   539→
   540→      case 'get_upcoming_events': {
   541→        const { CalendarSyncService } = await import('../calendar/CalendarSyncService.js');
   542→        const service = new CalendarSyncService();
   543→        const events = service.getCachedEvents(input.view);
   544→        if (events.length === 0) return `No ${input.view} events found`;
   545→        return `${input.view} events:\n${events.slice(0, 10).map((e) => `  - ${e.summary}`).join('\n')}`;
   546→      }
