   187→/**
   188→ * Refresh OAuth 2.0 access token
   189→ */
   190→export async function refreshOAuthToken(
   191→  refreshToken: string,
   192→  tokenUrl: string,
   193→  clientId: string,
   194→  clientSecret?: string
   195→): Promise<OAuthTokens> {
   196→  const params: any = {
   197→    refresh_token: refreshToken,
   198→    client_id: clientId,
   199→    grant_type: 'refresh_token',
   200→  };
   201→
   202→  if (clientSecret) {
   203→    params.client_secret = clientSecret;
   204→  }
   205→
   206→  const response = await fetch(tokenUrl, {
   207→    method: 'POST',
   208→    headers: {
   209→      'Content-Type': 'application/x-www-form-urlencoded',
   210→    },
   211→    body: new URLSearchParams(params).toString(),
   212→  });
   213→
   214→  if (!response.ok) {
   215→    const errorText = await response.text();
   216→    throw new Error(`Token refresh failed: ${errorText}`);
   217→  }
   218→
   219→  const tokens = await response.json();
   220→
   221→  // Calculate expiry date
   222→  if (tokens.expires_in) {
   223→    tokens.expiry_date = Date.now() + tokens.expires_in * 1000;
   224→  }
   225→
   226→  // Preserve refresh token if not returned
   227→  if (!tokens.refresh_token) {
   228→    tokens.refresh_token = refreshToken;
   229→  }
   230→
   231→  return tokens;
   232→}
