static async getAnthropicCredentials(): Promise<{ apiKey?: string; authToken?: string } | null> {
  const credentials = await CredentialManager.getCredentials('anthropic');
  if (!credentials) return null;

  const result: { apiKey?: string; authToken?: string } = {};
  if (credentials.api_key) result.apiKey = credentials.api_key;
  if (credentials.auth_token) result.authToken = credentials.auth_token;

  return Object.keys(result).length > 0 ? result : null;
}
```

